import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { FaEye, FaEyeSlash, FaSpinner } from 'react-icons/fa';

const Login = ({ onLogin }) => {
  const { t } = useTranslation();
  const [selectedRole, setSelectedRole] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [step, setStep] = useState('role'); // 'role' | 'credentials'
  const [isLoading, setIsLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');

  const roles = [
    {
      id: 'doctor',
      emoji: '👨‍⚕️',
      name: t('doctor') || 'Doctor',
      gradient: 'from-sky-500 to-cyan-500',
      usernamePrefix: 'd',
      sampleUsername: 'd001'
    },
    {
      id: 'patient',
      emoji: '👤',
      name: t('patient') || 'Patient',
      gradient: 'from-rose-500 to-orange-400',
      usernamePrefix: 'p',
      sampleUsername: 'p001'
    },
    {
      id: 'pharmacist',
      emoji: '💊',
      name: t('pharmacist') || 'Pharmacist',
      gradient: 'from-emerald-500 to-pink-400',
      usernamePrefix: 'pm',
      sampleUsername: 'pm001'
    }
  ];

  const handleRoleSelect = (role) => {
    setSelectedRole(role);
    setStep('credentials');
    setError('');
    setUsername('');
    setPassword('');
  };

  const handleLogin = async () => {
    if (!username || !password) {
      setError('Please enter both username and password');
      return;
    }
    
    setIsLoading(true);
    setError('');
    
    try {
      console.log('🔐 Attempting login with:', { username, role: selectedRole });
      
      // Username-only auth (no email supported)
      const payload = {
        username: username,
        password: password
      };
      
      const response = await fetch('http://localhost:5000/api/auth/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload)
      });
      
      console.log('📡 Response status:', response.status);
      
  let data = {};
      try {
        data = await response.json();
      } catch (e) {
        console.error('Failed to parse JSON response');
      }
      console.log('� Response data:', data);
      
      if (response.ok) {
        // Accept either 'token' or 'access_token' from backend
        const token = data.token || data.access_token;
        const user = data.user || {
          id: data.id || data.user_id,
          role: data.role || data.user_type,
          username: data.username || username,
        };
        
        if (!token) {
          throw new Error('Missing token in response');
        }
        
        // Store token and user in localStorage
        localStorage.setItem('token', token);
        localStorage.setItem('user', JSON.stringify(user));
        
        console.log('✅ Login successful, redirecting...');
        
        // Call onLogin with user data
        onLogin({
          ...user,
          token
        });
      } else {
        console.error('❌ Login failed:', data);
        // Normalize error message
        const serverMsg = data?.message || data?.error || 'Login failed';
        setError(serverMsg);
      }
    } catch (err) {
      console.error('🚨 Login error:', err);
      if (err.name === 'TypeError' && err.message.includes('fetch')) {
        setError('Unable to connect to server. Please ensure the backend is running on http://localhost:5000');
      } else {
        setError('Network error. Please check your connection and try again.');
      }
    } finally {
      setIsLoading(false);
    }
  };

  const getCurrentRole = () => {
    return roles.find(role => role.id === selectedRole);
  };

  const handleBack = () => {
    setStep('role');
    setSelectedRole('');
    setError('');
    setUsername('');
    setPassword('');
  };

  const getPasswordForRole = (role) => {
    switch (role) {
      case 'patient':
        return 'patient123';
      case 'doctor':
        return 'doctor123';
      case 'pharmacist':
        return 'pharmacy123';
      default:
        return '';
    }
  };

  const fillSampleCredentials = () => {
    const role = getCurrentRole();
    if (role) {
      setUsername(role.sampleUsername);
      setPassword(getPasswordForRole(selectedRole));
    }
  };
  return (
    <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4 font-sans">
      <div className="w-full max-w-md">
        {/* Hero */}
        <header className="text-center mb-6">
          <h1 className="text-3xl md:text-4xl font-extrabold text-gray-900 tracking-tight">
            Helio Healthcare Platform
          </h1>
          <p className="text-gray-600 mt-2 text-base">Choose Your Role</p>
        </header>

        {/* Card wrapper for content */}
        <div className="bg-white rounded-2xl shadow-lg border border-gray-100 p-4 sm:p-6">
          {/* Step 1: Role selection */}
          {step === 'role' && (
            <div>
              <div className="space-y-3 mb-5">
                {roles.map((role) => (
                  <button
                    key={role.id}
                    onClick={() => handleRoleSelect(role.id)}
                    className={`w-full relative overflow-hidden rounded-xl p-4 sm:p-5 text-left text-white font-bold shadow-sm transition-transform active:scale-[0.98] bg-gradient-to-r ${role.gradient}`}
                    aria-label={`Select ${role.name}`}
                  >
                    <div className="flex items-center gap-3">
                      <span className="text-2xl" aria-hidden> {role.emoji} </span>
                      <span className="text-lg sm:text-xl">{role.name}</span>
                    </div>
                  </button>
                ))}
              </div>

              {/* Demo Credentials Card */}
              <div className="rounded-xl border border-gray-200 bg-gray-50 p-4 sm:p-5 shadow-sm">
                <h3 className="text-center text-xl font-extrabold text-gray-900 mb-3">Demo Credentials</h3>
                <div className="space-y-3 text-sm sm:text-base">
                  <div className="flex items-start justify-between gap-3 p-3 bg-white rounded-lg border border-gray-200">
                    <div className="flex items-center gap-2">
                      <span className="text-xl">👨‍⚕️</span>
                      <span className="font-semibold text-gray-800">Doctors:</span>
                    </div>
                    <span className="font-mono text-gray-900">d001, d002, d003</span>
                  </div>
                  <div className="flex items-start justify-between gap-3 p-3 bg-white rounded-lg border border-gray-200">
                    <div className="flex items-center gap-2">
                      <span className="text-xl">👤</span>
                      <span className="font-semibold text-gray-800">Patients:</span>
                    </div>
                    <span className="font-mono text-gray-900">p001, p002, p003</span>
                  </div>
                  <div className="flex items-start justify-between gap-3 p-3 bg-white rounded-lg border border-gray-200">
                    <div className="flex items-center gap-2">
                      <span className="text-xl">💊</span>
                      <span className="font-semibold text-gray-800">Pharmacists:</span>
                    </div>
                    <span className="font-mono text-gray-900">pm001, pm002, pm003</span>
                  </div>
                </div>
              </div>

              {/* Default Passwords Card */}
              <div className="mt-4 rounded-xl border border-gray-200 bg-gradient-to-br from-white to-gray-50 p-4 sm:p-5 shadow-sm">
                <h4 className="text-gray-900 font-extrabold mb-3 flex items-center gap-2"><span>🔒</span> Default Passwords</h4>
                <div className="space-y-2 text-sm sm:text-base">
                  <div className="flex items-center justify-between gap-3 p-3 rounded-lg bg-white border border-gray-200">
                    <div className="flex items-center gap-2 text-gray-800 font-semibold"><span>👤</span> Patient: <span className="font-mono">p001</span></div>
                    <div className="font-mono font-bold text-gray-900">patient123</div>
                  </div>
                  <div className="flex items-center justify-between gap-3 p-3 rounded-lg bg-white border border-gray-200">
                    <div className="flex items-center gap-2 text-gray-800 font-semibold"><span>👨‍⚕️</span> Doctor: <span className="font-mono">d001</span></div>
                    <div className="font-mono font-bold text-gray-900">doctor123</div>
                  </div>
                  <div className="flex items-center justify-between gap-3 p-3 rounded-lg bg-white border border-gray-200">
                    <div className="flex items-center gap-2 text-gray-800 font-semibold"><span>💊</span> Pharmacist: <span className="font-mono">pm001</span></div>
                    <div className="font-mono font-bold text-gray-900">pharmacy123</div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Step 2: Credentials */}
          {step === 'credentials' && (
            <div className="space-y-5">
              <div className="text-center">
                <p className="text-sm text-gray-500 mb-1">Role</p>
                <h2 className="text-2xl font-extrabold text-gray-900">{getCurrentRole()?.name} Portal</h2>
              </div>

              {error && (
                <div className="p-3 rounded-lg bg-red-50 border border-red-200 text-red-800 text-sm">
                  {error}
                </div>
              )}

              <div className="space-y-4">
                <div>
                  <label className="block text-xs font-semibold text-gray-600 mb-1">Username</label>
                  <input
                    type="text"
                    value={username}
                    onChange={(e) => setUsername(e.target.value)}
                    placeholder={`e.g., ${getCurrentRole()?.sampleUsername}`}
                    className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:outline-none focus:ring-2 focus:ring-sky-200 focus:border-sky-400 text-base"
                    disabled={isLoading}
                  />
                </div>
                <div>
                  <label className="block text-xs font-semibold text-gray-600 mb-1">Password</label>
                  <div className="relative">
                    <input
                      type={showPassword ? 'text' : 'password'}
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      placeholder="Enter your password"
                      className="w-full px-4 py-3 pr-12 rounded-lg border border-gray-300 focus:outline-none focus:ring-2 focus:ring-sky-200 focus:border-sky-400 text-base"
                      disabled={isLoading}
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-gray-700"
                    >
                      {showPassword ? <FaEyeSlash /> : <FaEye />}
                    </button>
                  </div>
                </div>

                <div className="rounded-lg border border-dashed border-gray-300 p-3 flex items-center justify-between bg-gray-50">
                  <div>
                    <p className="text-sm font-semibold text-gray-700">Quick Demo Access</p>
                    <p className="text-xs text-gray-500">Auto-fill sample credentials</p>
                  </div>
                  <button
                    onClick={fillSampleCredentials}
                    className="px-3 py-2 rounded-md bg-gray-900 text-white text-sm font-bold disabled:opacity-50"
                    disabled={isLoading}
                  >
                    Fill ({getCurrentRole()?.sampleUsername})
                  </button>
                </div>

                <div className="flex gap-3 pt-2">
                  <button
                    onClick={handleBack}
                    className="flex-1 py-3 rounded-lg border border-gray-300 text-gray-800 font-bold"
                    disabled={isLoading}
                  >
                    Back
                  </button>
                  <button
                    onClick={handleLogin}
                    disabled={isLoading || !username || !password}
                    className="flex-1 py-3 rounded-lg text-white font-bold bg-gray-900 disabled:opacity-50 flex items-center justify-center gap-2"
                  >
                    {isLoading && <FaSpinner className="animate-spin" />}
                    {isLoading ? 'Authenticating…' : 'Secure Login'}
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Login;
